Rules.InvariantScript:
ClearCollect(
    colStaff,
    ForAll(
        Filter(
            Staff,
            Active = true &&
            Lower(Trim(Coalesce(Role.Value, ""))) <> "manager" &&
            (
                AidType.Value = "Work Study" ||
                AidType.Value = "Graduate Assistant" ||
                AidType.Value = "President's Aid"
            )
        ),
        {
            StaffID:        ID,
            MemberName:     Trim(
                                First(Split(Trim(Member.DisplayName), " ")).Value & " " &
                                Last(Split(Trim(Member.DisplayName), " ")).Value
                            ),
            MemberEmail:    Member.Email,
            Role:           Role,
            Active:         Active,
            AidType:        AidType.Value,
            SchedSortOrder: Coalesce(SchedSortOrder, 10)
        }
    )
);
ClearCollect(
    colShifts,
    ForAll(
        Filter(
            StaffShifts,
            StaffEmail <> "" &&
            !IsBlank(LookUp(colStaff, MemberEmail = StaffEmail))
        ),
        {
            ShiftID:    ID,
            Email:      StaffEmail,
            Day:        Day.Value,
            ShiftStart: ShiftStart.Value,
            ShiftEnd:   ShiftEnd.Value
        }
    )
);
ClearCollect(
    colSchedLookup,
    ForAll(
        colShifts As sh,
        With(
            {
                sr: LookUp(colStaff, MemberEmail = sh.Email),
                cr: LookUp(colSchedColors, Idx = Mod(LookUp(colStaff, MemberEmail = sh.Email).StaffID, 12))
            },
            {
                ShiftID:    sh.ShiftID,
                Email:      sh.Email,
                Name:       sr.MemberName,
                Initials:   Left(First(Split(Trim(sr.MemberName), " ")).Value, 1) &
                            Left(Last(Split(Trim(sr.MemberName), " ")).Value, 1),
                Day:        sh.Day,
                StartSlot:  Coalesce(LookUp(colTimeSlots, Label = sh.ShiftStart).Idx, -1),
                EndSlot:    Coalesce(LookUp(colTimeSlots, Label = sh.ShiftEnd).Idx, -1),
                ColorHex:   cr.Hex,
                ColorLight: cr.Light,
                SortOrder:  sr.SchedSortOrder
            }
        )
    )
);
Set(varSchedSelectedEmail, "");
Clear(colEditShifts);
Set(varSchedTotalsSortBy, "Student");
Set(varSchedTotalsSortDesc, false);
Set(varSchedScrollVersion, Coalesce(varSchedScrollVersion, 0) + 1)

If(
    IsBlank(drpSchedName.Selected),
    Set(varSchedSelectedEmail, "");
    Clear(colEditShifts),
    With(
        {em: drpSchedName.Selected.MemberEmail},
        Set(varSchedSelectedEmail, em);
        ClearCollect(
            colEditShifts,
            ForAll(
                Filter(colShifts, Email = em),
                {
                    RowKey:     Text(GUID()),
                    Day:        Day,
                    ShiftStart: ShiftStart,
                    ShiftEnd:   ShiftEnd
                }
            )
        );
        If(
            CountRows(colEditShifts) = 0,
            Collect(colEditShifts, {RowKey: Text(GUID()), Day: "Monday", ShiftStart: "8:30 AM", ShiftEnd: "9:00 AM"})
        )
    )
)

              Set(varSchedEditSaving, true);
RemoveIf(StaffShifts, StaffEmail = varSchedSelectedEmail);
Patch(
    StaffShifts,
    ForAll(
        Filter(colEditShifts, !IsBlank(ShiftStart) && !IsBlank(ShiftEnd)),
        {
            StaffEmail: varSchedSelectedEmail,
            Day:        {Value: Day},
            ShiftStart: {Value: ShiftStart},
            ShiftEnd:   {Value: ShiftEnd}
        }
    )
);
ClearCollect(
    colStaff,
    ForAll(
        Filter(
            Staff,
            Active = true &&
            Lower(Trim(Coalesce(Role.Value, ""))) <> "manager" &&
            (
                AidType.Value = "Work Study" ||
                AidType.Value = "Graduate Assistant" ||
                AidType.Value = "President's Aid"
            )
        ),
        {
            StaffID:        ID,
            MemberName:     Trim(
                                First(Split(Trim(Member.DisplayName), " ")).Value & " " &
                                Last(Split(Trim(Member.DisplayName), " ")).Value
                            ),
            MemberEmail:    Member.Email,
            Role:           Role,
            Active:         Active,
            AidType:        AidType.Value,
            SchedSortOrder: Coalesce(SchedSortOrder, 10)
        }
    )
);
ClearCollect(
    colShifts,
    ForAll(
        Filter(
            StaffShifts,
            StaffEmail <> "" &&
            !IsBlank(LookUp(colStaff, MemberEmail = StaffEmail))
        ),
        {
            ShiftID:    ID,
            Email:      StaffEmail,
            Day:        Day.Value,
            ShiftStart: ShiftStart.Value,
            ShiftEnd:   ShiftEnd.Value
        }
    )
);
ClearCollect(
    colSchedLookup,
    ForAll(
        colShifts As sh,
        With(
            {
                sr: LookUp(colStaff, MemberEmail = sh.Email),
                cr: LookUp(colSchedColors, Idx = Mod(LookUp(colStaff, MemberEmail = sh.Email).StaffID, 12))
            },
            {
                ShiftID:    sh.ShiftID,
                Email:      sh.Email,
                Name:       sr.MemberName,
                Initials:   Left(First(Split(Trim(sr.MemberName), " ")).Value, 1) &
                            Left(Last(Split(Trim(sr.MemberName), " ")).Value, 1),
                Day:        sh.Day,
                StartSlot:  Coalesce(LookUp(colTimeSlots, Label = sh.ShiftStart).Idx, -1),
                EndSlot:    Coalesce(LookUp(colTimeSlots, Label = sh.ShiftEnd).Idx, -1),
                ColorHex:   cr.Hex,
                ColorLight: cr.Light,
                SortOrder:  sr.SchedSortOrder
            }
        )
    )
);
Set(varSchedSelectedEmail, "");
Clear(colEditShifts);
Set(varSchedScrollVersion, Coalesce(varSchedScrollVersion, 0) + 1);
Set(varSchedEditSaving, false)

With(
    {
        aidType: drpSchedName.Selected.AidType,
        maxHrs:  Switch(drpSchedName.Selected.AidType, "Work Study", 12, "Graduate Assistant", 20, 6),
        hrs:     Sum(
            Filter(colEditShifts, !IsBlank(ShiftStart) && !IsBlank(ShiftEnd)),
            (LookUp(colTimeSlots, Label = ShiftEnd).Idx - LookUp(colTimeSlots, Label = ShiftStart).Idx) * 30 / 60
        )
    },
    aidType & " · " & If(hrs = RoundDown(hrs, 0), Text(hrs, "0"), Text(hrs, "0.#")) & " / " & Text(maxHrs, "0") & " hrs"
)

With(
    {
        maxHrs: Switch(drpSchedName.Selected.AidType, "Work Study", 12, "Graduate Assistant", 20, 6),
        hrs:    Sum(
            Filter(colEditShifts, !IsBlank(ShiftStart) && !IsBlank(ShiftEnd)),
            (LookUp(colTimeSlots, Label = ShiftEnd).Idx - LookUp(colTimeSlots, Label = ShiftStart).Idx) * 30 / 60
        )
    },
    If(hrs > maxHrs, varColorDanger, varColorText)
)
